using System.Collections.Generic;
using System.Collections.Immutable;
using Microsoft.CodeAnalysis.CSharp.Symbols;

namespace Microsoft.CodeAnalysis.CSharp
{
    /// <summary>
    /// Captures the result of a unified symbol resolution, including found symbols and any diagnostics.
    /// </summary>
    internal sealed class SymbolResolutionResult
    {
        /// <summary>
        /// The symbols found during resolution.
        /// </summary>
        public ImmutableArray<Symbol> Symbols { get; }

        /// <summary>
        /// Diagnostics produced during resolution.
        /// </summary>
        public ImmutableArray<Diagnostic> Diagnostics { get; }

        /// <summary>
        /// Whether the resolution found at least one viable symbol.
        /// </summary>
        public bool HasSymbols => !Symbols.IsDefaultOrEmpty;

        public SymbolResolutionResult(ImmutableArray<Symbol> symbols, ImmutableArray<Diagnostic> diagnostics)
        {
            Symbols = symbols.IsDefault ? ImmutableArray<Symbol>.Empty : symbols;
            Diagnostics = diagnostics.IsDefault ? ImmutableArray<Diagnostic>.Empty : diagnostics;
        }

        public static readonly SymbolResolutionResult Empty =
            new SymbolResolutionResult(ImmutableArray<Symbol>.Empty, ImmutableArray<Diagnostic>.Empty);
    }

    /// <summary>
    /// Strategy interface for resolving symbols in different binding contexts.
    /// </summary>
    internal interface ISymbolResolutionStrategy
    {
        /// <summary>
        /// Applies this strategy to look up symbols in a single binder scope.
        /// </summary>
        /// <param name="binder">The binder representing the current scope.</param>
        /// <param name="name">The symbol name to resolve.</param>
        /// <param name="arity">The arity (number of type parameters).</param>
        /// <param name="options">Lookup options.</param>
        /// <param name="result">The lookup result to populate.</param>
        /// <param name="originalBinder">The original binder that initiated the lookup.</param>
        /// <param name="diagnose">Whether to produce diagnostics.</param>
        /// <param name="useSiteInfo">Use-site diagnostics accumulator.</param>
        void LookupInSingleScope(
            Binder binder,
            string name,
            int arity,
            LookupOptions options,
            LookupResult result,
            Binder originalBinder,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo);
    }

    /// <summary>
    /// Strategy for resolving type symbols (classes, structs, interfaces, delegates, enums).
    /// </summary>
    internal sealed class TypeResolutionStrategy : ISymbolResolutionStrategy
    {
        public static readonly TypeResolutionStrategy Instance = new TypeResolutionStrategy();

        private TypeResolutionStrategy() { }

        public void LookupInSingleScope(
            Binder binder,
            string name,
            int arity,
            LookupOptions options,
            LookupResult result,
            Binder originalBinder,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            binder.LookupSymbolsInSingleBinder(
                result,
                name,
                arity,
                basesBeingResolved: null,
                options | LookupOptions.NamespacesOrTypesOnly,
                originalBinder,
                diagnose,
                ref useSiteInfo);
        }
    }

    /// <summary>
    /// Strategy for resolving member access on a qualifier (namespace or type).
    /// </summary>
    internal sealed class MemberAccessResolutionStrategy : ISymbolResolutionStrategy
    {
        private readonly NamespaceOrTypeSymbol _qualifier;

        public MemberAccessResolutionStrategy(NamespaceOrTypeSymbol qualifier)
        {
            _qualifier = qualifier;
        }

        public void LookupInSingleScope(
            Binder binder,
            string name,
            int arity,
            LookupOptions options,
            LookupResult result,
            Binder originalBinder,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            binder.LookupSymbolsInSingleBinder(
                result,
                name,
                arity,
                basesBeingResolved: null,
                options,
                originalBinder,
                diagnose,
                ref useSiteInfo);
        }

        /// <summary>
        /// The qualifier used for member access resolution.
        /// </summary>
        public NamespaceOrTypeSymbol Qualifier => _qualifier;
    }

    /// <summary>
    /// Strategy for resolving namespace symbols.
    /// </summary>
    internal sealed class NamespaceResolutionStrategy : ISymbolResolutionStrategy
    {
        public static readonly NamespaceResolutionStrategy Instance = new NamespaceResolutionStrategy();

        private NamespaceResolutionStrategy() { }

        public void LookupInSingleScope(
            Binder binder,
            string name,
            int arity,
            LookupOptions options,
            LookupResult result,
            Binder originalBinder,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            binder.LookupSymbolsInSingleBinder(
                result,
                name,
                arity,
                basesBeingResolved: null,
                options | LookupOptions.NamespacesOrTypesOnly | LookupOptions.NamespaceAliasesOnly,
                originalBinder,
                diagnose,
                ref useSiteInfo);
        }
    }

    /// <summary>
    /// Consolidates common symbol lookup patterns used across different binding contexts by walking
    /// the binder scope chain using a pluggable <see cref="ISymbolResolutionStrategy"/>.
    /// </summary>
    internal sealed class UnifiedSymbolResolver
    {
        private readonly Binder _rootBinder;

        public UnifiedSymbolResolver(Binder rootBinder)
        {
            _rootBinder = rootBinder;
        }

        /// <summary>
        /// Resolves symbols by walking the binder scope chain and applying the given strategy at
        /// each scope until a viable result is found.
        /// </summary>
        /// <param name="name">The symbol name to resolve.</param>
        /// <param name="arity">The arity (number of type parameters).</param>
        /// <param name="strategy">The resolution strategy to apply at each scope.</param>
        /// <param name="options">Additional lookup options.</param>
        /// <returns>A <see cref="SymbolResolutionResult"/> containing found symbols and diagnostics.</returns>
        public SymbolResolutionResult Resolve(
            string name,
            int arity,
            ISymbolResolutionStrategy strategy,
            LookupOptions options = LookupOptions.Default)
        {
            var useSiteInfo = CompoundUseSiteInfo<AssemblySymbol>.Discarded;

            // First pass: without diagnostics for performance.
            var result = LookupResult.GetInstance();
            WalkScopeChain(name, arity, strategy, options, result, diagnose: false, ref useSiteInfo);

            if (!result.IsMultiViable && !result.IsClear)
            {
                // Second pass: with diagnostics to get detailed failure information.
                result.Clear();
                WalkScopeChain(name, arity, strategy, options, result, diagnose: true, ref useSiteInfo);
            }

            var symbols = result.IsMultiViable
                ? result.Symbols.ToImmutableArray()
                : ImmutableArray<Symbol>.Empty;

            var diagnostics = result.Error != null
                ? ImmutableArray.Create<Diagnostic>(result.Error.ToDiagnostic(Location.None))
                : ImmutableArray<Diagnostic>.Empty;

            result.Free();

            return new SymbolResolutionResult(symbols, diagnostics);
        }

        private void WalkScopeChain(
            string name,
            int arity,
            ISymbolResolutionStrategy strategy,
            LookupOptions options,
            LookupResult result,
            bool diagnose,
            ref CompoundUseSiteInfo<AssemblySymbol> useSiteInfo)
        {
            for (var scope = _rootBinder; scope != null && !result.IsMultiViable; scope = scope.Next)
            {
                var tmp = result.IsClear ? result : LookupResult.GetInstance();
                strategy.LookupInSingleScope(scope, name, arity, options, tmp, _rootBinder, diagnose, ref useSiteInfo);

                if (!ReferenceEquals(tmp, result))
                {
                    result.MergeEqual(tmp);
                    tmp.Free();
                }
            }
        }
    }
}
