using System.Collections.Immutable;
using Microsoft.CodeAnalysis.CSharp.Symbols;
using Microsoft.CodeAnalysis.CSharp.Syntax;
using Microsoft.CodeAnalysis.CSharp.Test.Utilities;
using Microsoft.CodeAnalysis.Test.Utilities;
using Xunit;

namespace Microsoft.CodeAnalysis.CSharp.UnitTests.Semantics
{
    public class UnifiedSymbolResolverTests : CSharpTestBase
    {
        private static Binder GetRootBinder(CSharpCompilation compilation)
        {
            var tree = compilation.SyntaxTrees[0];
            return compilation.GetBinderFactory(tree)
                .GetInNamespaceBinder((CSharpSyntaxNode)tree.GetRoot());
        }

        [Fact]
        public void SymbolResolutionResult_Empty_HasNoSymbols()
        {
            var result = SymbolResolutionResult.Empty;
            Assert.False(result.HasSymbols);
            Assert.Empty(result.Symbols);
            Assert.Empty(result.Diagnostics);
        }

        [Fact]
        public void SymbolResolutionResult_WithSymbols_HasSymbols()
        {
            var compilation = CreateCompilation("class C { }");
            var typeSymbol = compilation.GlobalNamespace.GetTypeMembers("C")[0];
            var symbols = ImmutableArray.Create<Symbol>(typeSymbol);
            var result = new SymbolResolutionResult(symbols, ImmutableArray<Diagnostic>.Empty);

            Assert.True(result.HasSymbols);
            Assert.Single(result.Symbols);
            Assert.Equal("C", result.Symbols[0].Name);
        }

        [Fact]
        public void SymbolResolutionResult_DefaultSymbolsHandled()
        {
            // Default ImmutableArray should be treated as empty.
            var result = new SymbolResolutionResult(
                default(ImmutableArray<Symbol>),
                default(ImmutableArray<Diagnostic>));

            Assert.False(result.HasSymbols);
            Assert.Empty(result.Symbols);
            Assert.Empty(result.Diagnostics);
        }

        [Fact]
        public void TypeResolutionStrategy_IsSingleton()
        {
            Assert.NotNull(TypeResolutionStrategy.Instance);
            Assert.Same(TypeResolutionStrategy.Instance, TypeResolutionStrategy.Instance);
        }

        [Fact]
        public void NamespaceResolutionStrategy_IsSingleton()
        {
            Assert.NotNull(NamespaceResolutionStrategy.Instance);
            Assert.Same(NamespaceResolutionStrategy.Instance, NamespaceResolutionStrategy.Instance);
        }

        [Fact]
        public void MemberAccessResolutionStrategy_StoresQualifier()
        {
            var compilation = CreateCompilation("class C { }");
            NamespaceOrTypeSymbol qualifier = compilation.GlobalNamespace;
            var strategy = new MemberAccessResolutionStrategy(qualifier);

            Assert.Same(qualifier, strategy.Qualifier);
        }

        [Fact]
        public void UnifiedSymbolResolver_ReturnsEmpty_WhenSymbolNotFound()
        {
            var compilation = CreateCompilation("class C { }");
            var binder = GetRootBinder(compilation);
            var resolver = new UnifiedSymbolResolver(binder);

            var result = resolver.Resolve("NonExistentSymbol12345", 0, TypeResolutionStrategy.Instance);

            Assert.NotNull(result);
            Assert.False(result.HasSymbols);
        }

        [Fact]
        public void UnifiedSymbolResolver_Resolve_ReturnsNonNull()
        {
            var source = @"
namespace MyNS
{
    class MyClass { }
}
";
            var compilation = CreateCompilation(source);
            var binder = GetRootBinder(compilation);
            var resolver = new UnifiedSymbolResolver(binder);

            var result = resolver.Resolve("MyNS", 0, NamespaceResolutionStrategy.Instance);

            Assert.NotNull(result);
        }

        [Fact]
        public void ISymbolResolutionStrategy_ImplementedByAllConcreteStrategies()
        {
            var compilation = CreateCompilation("namespace N { class C { } }");
            NamespaceOrTypeSymbol qualifier = compilation.GlobalNamespace;

            ISymbolResolutionStrategy typeStrategy = TypeResolutionStrategy.Instance;
            ISymbolResolutionStrategy nsStrategy = NamespaceResolutionStrategy.Instance;
            ISymbolResolutionStrategy memberStrategy = new MemberAccessResolutionStrategy(qualifier);

            Assert.NotNull(typeStrategy);
            Assert.NotNull(nsStrategy);
            Assert.NotNull(memberStrategy);
        }

        [Fact]
        public void UnifiedSymbolResolver_Resolve_WithDifferentArities()
        {
            var compilation = CreateCompilation("class C { }");
            var binder = GetRootBinder(compilation);
            var resolver = new UnifiedSymbolResolver(binder);

            // Arity 0 (non-generic type)
            var result0 = resolver.Resolve("C", 0, TypeResolutionStrategy.Instance);
            Assert.NotNull(result0);

            // Arity 1 (generic type, won't match C, should return empty)
            var result1 = resolver.Resolve("C", 1, TypeResolutionStrategy.Instance);
            Assert.NotNull(result1);
        }
    }
}

